 1	import React, { FC } from 'react';
 2	
 3	import SidebarEditor from '@kubevirt-utils/components/SidebarEditor/SidebarEditor';
 4	import { PATHS_TO_HIGHLIGHT } from '@kubevirt-utils/resources/vm/utils/constants';
 5	import { PageSection, PageSectionVariants } from '@patternfly/react-core';
 6	
 7	import { ConfigurationInnerTabProps } from '../utils/types';
 8	
 9	import { onSubmitYAML } from './utils/utils';
10	import DetailsSection from './DetailsSection';
11	
12	const DetailsTab: FC<ConfigurationInnerTabProps> = ({
13	  allInstanceTypes,
14	  instanceTypeVM,
15	  vm,
16	  vmi,
17	}) => (
18	  <SidebarEditor
19	    onResourceUpdate={onSubmitYAML}
20	    pathsToHighlight={PATHS_TO_HIGHLIGHT.DETAILS_TAB}
21	    resource={vm}
22	  >
23	    {(resource) => (
24	      <PageSection variant={PageSectionVariants.light}>
25	        <DetailsSection
26	          allInstanceTypes={allInstanceTypes}
27	          instanceTypeVM={instanceTypeVM}
28	          vm={resource}
29	          vmi={vmi}
30	        />
31	      </PageSection>
32	    )}
33	  </SidebarEditor>
34	);
35	
36	export default DetailsTab;

